var theInputGameQuestionList = [
  InputGameQuestion(0, "没有比赛。",""),
  InputGameQuestion(1, "这个男孩是学生，也是咖啡店的服务员。那个女孩是他妹妹。","這個男孩是學生，也是咖啡店的服務員。那個女孩是他妹妹。"),
  InputGameQuestion(2, "一些生活在水里的动物，用贝壳保护自己的身体。甲骨文中的贝字就像一种海贝的样子。", "一些生活在水裡的動物，用貝殼保護自己的身體。甲骨文中的貝字就像一種海貝的樣子。"),
  InputGameQuestion(3, "为了看日出，我常常早起。那时天还没有大亮，周围非常清静，船上只有机器的响声。天空还是一片浅蓝，颜色很浅。转眼间天边出现了一道红霞，慢慢地在扩大它的范围，加强它的亮光。我知道太阳要从天边升起来了，便不转眼地望着那里。", "為了看日出，我常常早起。那時天還沒有大亮，周圍非常清靜，船上只有機器的響聲。天空還是一片淺藍，顏色很淺。轉眼間天邊出現了一道紅霞，慢慢地在擴大它的範圍，加強它的亮光。我知道太陽要從天邊升起來了，便不轉眼地望著那裡。"),
  InputGameQuestion(4, "第二天早晨，船驶进邻国宏伟都城的港口。所有教堂的钟都敲响了，高高的塔顶上军号齐鸣，兵士们拿着飘扬的旗子，佩带着闪亮的军刀在敬礼。每天都有欢庆活动，宴会和舞会一个接着一个，可是公主还没有露面。人们说她在一个遥远的地方接受教育，学习各种皇家的美德。最后，她终于来了。室冷灯昏，夜深风急。墙暗影动，窗细声微。被轻难御，露重衣湿。身寒手僵，心惊梦迟。", "第二天早晨，船駛進鄰國宏偉都城的港口。所有教堂的鐘都敲響了，高高的塔頂上軍號齊鳴，兵士們拿著飄揚的旗子，佩帶著閃亮的軍刀在敬禮。每天都有歡慶活動，宴會和舞會一個接著一個，可是公主還沒有露面。人們說她在一個遙遠的地方接受教育，學習各種皇家的美德。最後，她終於來了。"),
  InputGameQuestion(5, "你好！我叫王中，今年十五岁。很高兴认识你。","你好！我叫王中，今年十五歲。很高興認識你。"),
  InputGameQuestion(6, "我住在上海，它是一个热闹的大城市。每天上学，我会经过公园，看小朋友玩耍。学校里有很多老师和同学，大家都很友好。周末时，我会和家人去南京路走走。", "我住在上海，它是一個熱鬧的大城市。每天上學，我會經過公園，看小朋友玩耍。學校裡有很多老師和同學，大家都很友好。週末時，我會和家人去南京路走走。"),
  InputGameQuestion(7, "有一次放学以后，天空忽然下起了大雨，我没有带伞，只好站在路边等雨停。雨越下越大，地面很快被打湿，空气也渐渐变得清凉。来往的人有的急忙跑开，有的停下来避雨，还有人放慢脚步继续前行。我站在那里，看着眼前的变化，原本有些着急的心情慢慢平静下来，觉得这样的时刻也很特别。","有一次放學以後，天空忽然下起了大雨，我沒有帶傘，只好站在路邊等雨停。雨越下越大，地面很快被打濕，空氣也漸漸變得清涼。來往的人有的急忙跑開，有的停下來避雨，還有人放慢腳步繼續前行。我站在那裡，看著眼前的變化，原本有些著急的心情慢慢平靜下來，覺得這樣的時刻也很特別。"),
  InputGameQuestion(8, "暮色渐渐降临，小城被一层柔和的橙光笼罩。那家有些陈旧的书店静静立在街角，门上的铜铃随风轻轻作响。店主老人目光平静，仿佛有着许多没有说出的往事。一位旅人偶然推门走入，在积着灰尘的书页间发现一封未寄出的信，字迹温和却略显匆忙。信中讲述了一段未完成的告别，也留下一个无人回答的疑问。风从门缝吹进，纸页轻轻翻动，仿佛有人低声回应。", "暮色漸漸降臨，小城被一層柔和的橙光籠罩。那家有些陳舊的書店靜靜立在街角，門上的銅鈴隨風輕輕作響。店主老人目光平靜，彷彿有著許多沒有說出的往事。一位旅人偶然推門走入，在積著灰塵的書頁間發現一封未寄出的信，字跡溫和卻略顯匆忙。信中講述了一段未完成的告別，也留下了一個無人回答的疑問。風從門縫吹進，紙頁輕輕翻動，彷彿有人低聲回應。"),
  InputGameQuestion(9, "放学以后，几个同学一起留在教室整理活动材料。有人负责写海报，有人搬桌椅，还有人检查音响设备。窗外天色慢慢变暗，校园里却越来越热闹，大家都期待第二天的演出能够顺利进行。",""),
  InputGameQuestion(10, "许多动物都会利用自己的身体特点适应环境。北极熊拥有厚厚的白色皮毛，可以帮助它们抵抗寒冷，也方便隐藏在冰雪之中。骆驼则能够在缺水情况下长时间行走，因为它们的身体能够储存能量并减少水分流失，因此特别适合生活在沙漠地区。",""),
  InputGameQuestion(11, "清晨的大海还没有完全苏醒，远处只能听见海浪缓慢拍打礁石的声音。几只海鸥在灰蓝色天空下盘旋，不时落到岸边寻找食物。渔船陆续离开港口，发动机低沉而连续的轰鸣声打破了原本的安静。随着太阳一点一点升起，海面渐渐出现闪烁而耀眼的金色波光，潮湿微凉的海风也慢慢吹遍整座临海的小城。",""),
  InputGameQuestion(12, "晋太元中，武陵人捕鱼为业。缘溪行，忘路之远近。忽逢桃花林，夹岸数百步，中无杂树，芳草鲜美，落英缤纷。渔人甚异之，复前行，欲穷其林。林尽水源，便得一山，山有小口，仿佛若有光。便舍船，从口入。初极狭，才通人。复行数十步，豁然开朗。", ""),
];